CREATE PROC [dbo].[TR_AI_CODE_UPDATE]
(
	@id_ai nvarchar(50),
	@ten_ai nvarchar(200),
	@masp nvarchar(MAX),
	@hehang nvarchar(MAX),
	@file_dinhkem nvarchar(MAX),
	@ngaytao datetime,
	@nguoitao nvarchar(50),
	@ngaysua datetime,
	@nguoisua nvarchar(50),
	@active bit
)
AS
UPDATE tr_ai_code
SET
	ten_ai = @ten_ai,
	masp = @masp,
	hehang = @hehang,
	file_dinhkem = @file_dinhkem,
	ngaysua = @ngaysua,
	nguoisua = @nguoisua,
	active = @active
WHERE id_ai = @id_ai


DECLARE @CNT INT
SELECT @CNT = COUNT(mavt)
FROM tr_material 
WHERE mavt = @id_ai

IF @CNT = 0
BEGIN
    INSERT INTO tr_material
    (
	   idxuong, 
	   mavt, 
	   tenvt, 
	   mota,
	   dvt, 
	   nhom, 
	   kho, 
	   xoa,
	   create_by, 
	   create_date, 
	   update_by, 
	   update_date
    )
    VALUES
    (
	   @id_ai, 
	   @id_ai, 
	   @ten_ai, 
	   @ten_ai,
	   N'Bộ', 
	   'AI', 
	   N'NGŨ KIM', 
	   'N',
	   @nguoitao, 
	   @ngaytao, 
	   @nguoisua, 
	   @ngaysua
    )
END
ELSE
BEGIN
    UPDATE tr_material
    SET tenvt = @ten_ai,
	   mota = @ten_ai,
	   update_by = @nguoisua,
	   update_date = @ngaysua
    WHERE mavt = @id_ai
END
